Salut! Dans le monde de la programmation C++, si tu veux créer un nouveau processus avec un seul file descriptor connecté à son entrée et à sa sortie, tu peux utiliser la fonction `fork()` pour créer le processus fils, et ensuite utiliser `dup2()` pour rediriger l'entrée et la sortie vers le même file descriptor. Voici un exemple simple :

```cpp
#include <unistd.h>
#include <iostream>
#include <cstdlib>

int main() {
    int pipefd[2];
    if (pipe(pipefd) == -1) {
        std::cerr << "Erreur création pipe" << std::endl;
        return 1;
    }

    pid_t pid = fork();
    if (pid == -1) {
        std::cerr << "Erreur fork" << std::endl;
        return 1;
    }

    if (pid == 0) { // Fils
        close(pipefd[1]); // Ferme l'écriture parent
        dup2(pipefd[0], 0); // Redirige l'entrée vers le pipe (entrée)
        dup2(pipefd[0], 1); // Redirige la sortie vers le pipe (sortie)

        close(pipefd[0]); // Ferme le file descriptor du pipe non nécessaire

        execlp("ls", "ls", NULL); // Remplace le processus par "ls"
        std::cerr << "Erreur exécution" << std::endl;
        return 1;
    } else { // Parent
        close(pipefd[0]); // Ferme l'entrée parent

        // Écrit quelque chose dans le pipe
        std::string message = "Bonjour, monde!\n";
        write(pipefd[1], message.c_str(), message.size());

        close(pipefd[1]); // Ferme l'écriture parent

        wait(NULL); // Attends que le processus fils termine
        return 0;
    }
}
```

Cet exemple crée un pipe, redirige l'entrée et la sortie du processus fils vers le pipe, et fait exécuter "ls" dans le processeur fils. Le processus parent écrira ensuite une chaîne de caractères dans le pipe, qui sera lue par "ls".

